mapper.select:
SELECT wf_process.*, t_eav_entity.`name` as formName,t_category.name as categoryName FROM wf_process LEFT JOIN t_eav_entity ON t_eav_entity.id = wf_process.form_type LEFT JOIN t_category ON t_category.id = wf_process.category_id WHERE 1=1
AND wf_process.name LIKE CONCAT('%',#{name},'%')
AND (wf_process.name LIKE CONCAT('%',#{search},'%') or t_eav_entity.`name` LIKE CONCAT('%',#{search},'%') )
AND wf_process.status = #{status}
AND wf_process.form_type = #{formType}
And wf_process.org_id = #{orgId}
ORDER BY wf_process.id ASC
